import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Login from './subfolder/Login';
import Nav from './subfolder/Nav';  // Import merged Nav component
import ContactUs from './subfolder/Contactus';
import Signup from './subfolder/Signup';
import AboutUs from './subfolder/About';
import HomeP from './subfolder/HomeP';
import Homed from './subfolder/Homed';
import Footer from './subfolder/Footer';
import Package2 from './subfolder/package2';

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  return (
    <Router>
      {/* Pass isLoggedIn and setIsLoggedIn to Nav */}
      <Nav isLoggedIn={isLoggedIn} setIsLoggedIn={setIsLoggedIn} />

      <Routes>
        {/* Public Routes (for logged-out users) */}
        {!isLoggedIn ? (
          <>
            <Route path="/" element={<HomeP />} />  {/* Logged-out Home Page */}
            <Route path="/login" element={<Login setIsLoggedIn={setIsLoggedIn} />} />
            <Route path="/aboutus" element={<AboutUs />} />
            <Route path="/contact" element={<ContactUs />} />
            <Route path="/create-account" element={<Signup />} />
          </>
        ) : (
          <>
            {/* Private Routes (for logged-in users) */}
            <Route path="/" element={<Homed />} />  {/* Logged-in Home Page */}
            <Route path="/aboutus" element={<AboutUs />} />
            <Route path="/contact" element={<ContactUs />} />
          </>
        )}

        <Route path="/package-details" element={<Package2 />} /> {/* Package2 Route */}
      </Routes>

      <Footer />
    </Router>
  );
}

export default App;
